      <div class="jiranimo-about-header">
        <span class="jiranimo-about-logo">${SPARKLES_SVG}</span>
        <h2 class="jiranimo-about-title">Jiranimo</h2>
        <button class="jiranimo-about-close" title="Close (Esc)">&times;</button>
