     1→/**
     2→ * E2E tests for the Chrome extension UI.
     3→ * Uses Playwright to render a mock Jira board, inject extension scripts,
     4→ * and take real PNG screenshots of the config modal and badges.
     5→ */
     6→
     7→import { describe, it, expect, afterAll, beforeAll } from 'vitest';
     8→import { chromium, type Browser, type Page } from 'playwright';
     9→import { createServer, type Server } from 'node:http';
    10→import { readFileSync } from 'node:fs';
    11→import { resolve, join } from 'node:path';
    12→import { mkdirSync, rmSync, existsSync } from 'node:fs';
    13→
    14→const EXTENSION_DIR = resolve(import.meta.dirname, '..', '..', '..', 'extension');
    15→const FIXTURES_DIR = resolve(import.meta.dirname, 'fixtures');
    16→const SCREENSHOTS_DIR = resolve(import.meta.dirname, 'screenshots', 'extension-ui');
    17→
    18→let browser: Browser;
    19→let server: Server;
    20→let serverPort: number;
    21→let stepCounter = 0;
    22→
    23→const BOARD_URL = () => `http://127.0.0.1:${serverPort}/jira/software/projects/JTEST/boards/1`;
    24→const extUrl = (path: string) => `http://127.0.0.1:${serverPort}/ext/${path}`;
    25→
    26→function screenshotPath(testName: string, phase: string): string {
    27→  stepCounter++;
